function slug(text) {
  return text.toLowerCase().replace(/[^a-z0-9]+/g, "-").replace(/^-|-$/g, "");
}

function readStore(key) {
  const raw = localStorage.getItem(key);
  return raw ? JSON.parse(raw) : [];
}

function writeStore(key, value) {
  localStorage.setItem(key, JSON.stringify(value));
}

function loadRecipes() {
  const custom = readStore("chef_deluxe_custom_recipes");
  return [...starterRecipes, ...custom];
}

let recipes = loadRecipes();

const state = {
  category: "All",
  search: "",
  favouritesOnly: false
};

const grid = document.getElementById("recipeGrid");
const searchInput = document.getElementById("searchInput");
const categoryFilters = document.getElementById("categoryFilters");
const recipeCount = document.getElementById("recipeCount");
const modal = document.getElementById("recipeModal");
const modalContent = document.getElementById("modalContent");
const closeModalBtn = document.getElementById("closeModalBtn");
const surpriseBtn = document.getElementById("surpriseBtn");
const addRecipeBtn = document.getElementById("addRecipeBtn");
const favouritesBtn = document.getElementById("favouritesBtn");
const generatorBtn = document.getElementById("generatorBtn");

const addModal = document.getElementById("addModal");
const closeAddModalBtn = document.getElementById("closeAddModalBtn");
const saveRecipeBtn = document.getElementById("saveRecipeBtn");
const cancelAddBtn = document.getElementById("cancelAddBtn");

const generatorModal = document.getElementById("generatorModal");
const closeGeneratorModalBtn = document.getElementById("closeGeneratorModalBtn");
const cancelGeneratorBtn = document.getElementById("cancelGeneratorBtn");
const makeRecipeBtn = document.getElementById("makeRecipeBtn");

function getFavourites() {
  return readStore("chef_deluxe_favourites");
}

function isFavourite(id) {
  return getFavourites().includes(id);
}

function toggleFavourite(id) {
  const current = getFavourites();
  const next = current.includes(id) ? current.filter(x => x !== id) : [id, ...current];
  writeStore("chef_deluxe_favourites", next);
  renderRecipes();
  if (!modal.classList.contains("hidden")) {
    openRecipe(id);
  }
}

function getCategories() {
  const categories = recipes.map(r => r.category).filter(Boolean);
  return ["All", ...new Set(categories)];
}

function saveCustomRecipe(recipe) {
  const current = readStore("chef_deluxe_custom_recipes");
  current.unshift(recipe);
  writeStore("chef_deluxe_custom_recipes", current);
  recipes = loadRecipes();
}

function renderFilters() {
  const categories = getCategories();
  categoryFilters.innerHTML = categories.map(category => `
    <button class="chip ${state.category === category ? "active" : ""}" data-category="${category}">
      ${category}
    </button>
  `).join("");

  categoryFilters.querySelectorAll(".chip").forEach(btn => {
    btn.addEventListener("click", () => {
      state.category = btn.dataset.category;
      renderFilters();
      renderRecipes();
    });
  });

  favouritesBtn.classList.toggle("active", state.favouritesOnly);
  favouritesBtn.textContent = state.favouritesOnly ? "⭐ Favourites on" : "⭐ Favourites";
}

function matchesRecipe(recipe) {
  const haystack = [
    recipe.title,
    recipe.category,
    recipe.description,
    recipe.difficulty,
    ...(recipe.tags || []),
    ...(recipe.ingredients || []),
    ...(recipe.notes || []),
    ...(recipe.plating || []),
    ...((recipe.steps || []).map(step => `${step.title} ${step.body}`))
  ].join(" ").toLowerCase();

  const searchOk = !state.search || haystack.includes(state.search.toLowerCase());
  const categoryOk = state.category === "All" || recipe.category === state.category;
  const favouriteOk = !state.favouritesOnly || isFavourite(recipe.id);
  return searchOk && categoryOk && favouriteOk;
}

function renderRecipes() {
  const filtered = recipes.filter(matchesRecipe);
  recipeCount.textContent = recipes.length;

  if (!filtered.length) {
    grid.innerHTML = `<div class="empty-state"><h3>No recipes found</h3><p>Try another category, switch off favourites, or search for a different ingredient or dish.</p></div>`;
    return;
  }

  grid.innerHTML = filtered.map(recipe => `
    <article class="recipe-card" id="${recipe.id}">
      <div class="recipe-top">
        <span class="category-badge">${recipe.category}</span>
        <span class="level-badge">${recipe.difficulty}</span>
      </div>
      <h3>${recipe.title}</h3>
      <p class="recipe-desc short">${recipe.description}</p>

      <div class="recipe-meta-row">
        <div class="time-badge">⏱ ${recipe.time}</div>
        <div class="serving-badge">🍽 ${recipe.serves}</div>
      </div>

      <div class="recipe-tags">
        ${(recipe.tags || []).map(tag => `<span class="tag">${tag}</span>`).join("")}
      </div>

      <div class="recipe-card-actions">
        <button class="primary-btn" onclick="openRecipe('${recipe.id}')">Open full recipe</button>
        <button class="ghost-btn favorite-btn ${isFavourite(recipe.id) ? "active" : ""}" onclick="toggleFavourite('${recipe.id}')">
          ${isFavourite(recipe.id) ? "★ Saved" : "☆ Save"}
        </button>
      </div>
    </article>
  `).join("");
}

function openRecipe(recipeId) {
  const recipe = recipes.find(r => r.id === recipeId);
  if (!recipe) return;

  modalContent.innerHTML = `
    <section class="recipe-hero">
      <div class="hero-topline">${recipe.category} recipe</div>
      <h2>${recipe.title}</h2>
      <p>${recipe.description}</p>

      <div class="quick-info-grid">
        <div class="info-card"><span class="info-label">Difficulty</span><span class="info-value">${recipe.difficulty}</span></div>
        <div class="info-card"><span class="info-label">Cook time</span><span class="info-value">${recipe.time}</span></div>
        <div class="info-card"><span class="info-label">Serves</span><span class="info-value">${recipe.serves}</span></div>
        <div class="info-card"><span class="info-label">Style</span><span class="info-value">${recipe.tags && recipe.tags.length ? recipe.tags[0] : "Chef at home"}</span></div>
      </div>
    </section>

    <section class="recipe-layout">
      <div class="panel">
        <h3>Ingredients</h3>
        <div class="ingredients-grid">
          ${(recipe.ingredients || []).map(item => `<div class="ingredient-item"><span class="bullet"></span><div>${item}</div></div>`).join("")}
        </div>

        <div class="notes-grid">
          <h3>Pro tips</h3>
          ${(recipe.notes || []).map(note => `<div class="note-item"><span class="bullet"></span><div>${note}</div></div>`).join("")}
        </div>
      </div>

      <div class="panel">
        <h3>Step-by-step method</h3>
        <div class="steps-list">
          ${(recipe.steps || []).map((step, index) => `
            <article class="step-card">
              <div class="step-head">
                <div class="step-number">${index + 1}</div>
                <div class="step-title">${step.title}</div>
                <div class="step-badges">
                  <span class="badge">🔥 ${step.heat}</span>
                  <span class="badge">⏱ ${step.time}</span>
                </div>
              </div>
              <div class="step-body">${step.body}</div>
            </article>
          `).join("")}
        </div>
      </div>
    </section>

    <section class="panel">
      <h3>Plating & finishing</h3>
      ${(recipe.plating || []).map(item => `<div class="note-item"><span class="bullet"></span><div>${item}</div></div>`).join("")}
    </section>

    <div class="footer-actions">
      <button class="primary-btn" onclick="toggleFavourite('${recipe.id}')">${isFavourite(recipe.id) ? "★ Remove from saved" : "☆ Save recipe"}</button>
      <button class="secondary-btn" onclick="window.print()">Print recipe</button>
      <button class="secondary-btn" onclick="closeRecipe()">Done</button>
    </div>
  `;
  modal.classList.remove("hidden");
  modal.setAttribute("aria-hidden", "false");
  document.body.classList.add("modal-open");
}

function closeRecipe() {
  modal.classList.add("hidden");
  modal.setAttribute("aria-hidden", "true");
  document.body.classList.remove("modal-open");
}

function openAddModal() {
  addModal.classList.remove("hidden");
  addModal.setAttribute("aria-hidden", "false");
  document.body.classList.add("modal-open");
}

function closeAddModal() {
  addModal.classList.add("hidden");
  addModal.setAttribute("aria-hidden", "true");
  document.body.classList.remove("modal-open");
}

function openGeneratorModal() {
  generatorModal.classList.remove("hidden");
  generatorModal.setAttribute("aria-hidden", "false");
  document.body.classList.add("modal-open");
}

function closeGeneratorModal() {
  generatorModal.classList.add("hidden");
  generatorModal.setAttribute("aria-hidden", "true");
  document.body.classList.remove("modal-open");
}

function getLines(id) {
  return document.getElementById(id).value.split("\n").map(x => x.trim()).filter(Boolean);
}

function buildGeneratedRecipe() {
  const ingredients = getLines("gIngredients");
  const style = document.getElementById("gStyle").value.trim() || "Chef special";
  const category = document.getElementById("gCategory").value.trim() || "Custom";
  const difficulty = document.getElementById("gDifficulty").value.trim() || "Custom";
  const time = document.getElementById("gTime").value.trim() || "30 min";
  const serves = document.getElementById("gServes").value.trim() || "2 people";

  if (!ingredients.length) {
    alert("Add at least one ingredient first.");
    return;
  }

  const lead = ingredients[0];
  const styleWord = style.split(" ")[0];
  const title = `${styleWord.charAt(0).toUpperCase() + styleWord.slice(1)} ${lead.charAt(0).toUpperCase() + lead.slice(1)}`;
  const lowerList = ingredients.join(", ");

  const recipe = {
    id: slug(title + "-" + Date.now()),
    title,
    category,
    difficulty,
    time,
    serves,
    description: `A custom ${style.toLowerCase()} recipe built from ${lowerList} and saved straight into your cookbook.`,
    tags: [category || "Custom", "Generated", "Step-by-step"],
    ingredients,
    notes: [
      "Prep everything before the heat goes on so you can cook with control.",
      "Taste before serving and use salt or acid to wake up flat flavour.",
      "If colour builds too fast, lower the heat slightly and steady the pan."
    ],
    steps: [
      {
        title: "Prep the ingredients",
        heat: "No heat",
        time: "5 min",
        body: "Cut and organise everything first so the cooking flow stays calm and deliberate."
      },
      {
        title: "Start the flavour base",
        heat: "Medium-high",
        time: "3-5 min",
        body: `Warm the pan, add your first flavour ingredients, and build some colour without burning anything. With ${lead.toLowerCase()}, look for a lively sizzle rather than a pale start.`
      },
      {
        title: "Build the dish",
        heat: "Medium",
        time: "6-10 min",
        body: "Add the rest of the ingredients in the order they need cooking, keeping an eye on texture as the dish comes together. The goal is balanced flavour, not just speed."
      },
      {
        title: "Finish and balance",
        heat: "Low-medium",
        time: "2-4 min",
        body: "Taste, correct the seasoning, and stop only when the dish looks glossy, smells rounded, and feels properly cooked."
      }
    ],
    plating: [
      "Keep the plate tidy and wipe the rim before serving.",
      "Use height or a neat central placement so the dish looks intentional.",
      "Finish with a fresh element, herb, or final drizzle for contrast."
    ]
  };

  saveCustomRecipe(recipe);
  renderFilters();
  renderRecipes();
  closeGeneratorModal();

  ["gIngredients","gStyle","gCategory","gDifficulty","gTime","gServes"].forEach(id => {
    document.getElementById(id).value = "";
  });

  openRecipe(recipe.id);
}

function saveNewRecipe() {
  const title = document.getElementById("fTitle").value.trim();
  const category = document.getElementById("fCategory").value.trim() || "Custom";
  const difficulty = document.getElementById("fDifficulty").value.trim() || "Custom";
  const time = document.getElementById("fTime").value.trim() || "Not set";
  const serves = document.getElementById("fServes").value.trim() || "Not set";
  const description = document.getElementById("fDescription").value.trim() || "A user-added recipe.";
  const tags = document.getElementById("fTags").value.split(",").map(x => x.trim()).filter(Boolean);
  const ingredients = getLines("fIngredients");
  const notes = getLines("fNotes");
  const rawSteps = getLines("fSteps");

  if (!title) {
    alert("Add a recipe name first.");
    return;
  }

  const steps = rawSteps.map((line, i) => {
    const parts = line.split("|").map(x => x.trim());
    return {
      title: parts[0] || `Step ${i + 1}`,
      heat: parts[1] || "Medium",
      time: parts[2] || "",
      body: parts[3] || parts[0] || ""
    };
  });

  if (!steps.length) {
    alert("Add at least one step.");
    return;
  }

  const newRecipe = {
    id: slug(title + "-" + Date.now()),
    title,
    category,
    difficulty,
    time,
    serves,
    description,
    tags: tags.length ? tags : ["Custom"],
    ingredients: ingredients.length ? ingredients : ["Add ingredients"],
    notes: notes.length ? notes : ["Taste as you go and steady the heat if the pan gets too aggressive."],
    steps,
    plating: [
      "Use a clean plate and wipe the rim before serving.",
      "Keep the food grouped neatly rather than spread out randomly.",
      "Finish with a final garnish or contrast if the dish needs colour."
    ]
  };

  saveCustomRecipe(newRecipe);
  renderFilters();
  renderRecipes();
  closeAddModal();

  ["fTitle","fCategory","fDifficulty","fTime","fServes","fDescription","fTags","fIngredients","fNotes","fSteps"].forEach(id => {
    document.getElementById(id).value = "";
  });
}

searchInput.addEventListener("input", (e) => {
  state.search = e.target.value.trim();
  renderRecipes();
});

closeModalBtn.addEventListener("click", closeRecipe);
modal.querySelector(".modal-backdrop").addEventListener("click", closeRecipe);

addRecipeBtn.addEventListener("click", openAddModal);
closeAddModalBtn.addEventListener("click", closeAddModal);
addModal.querySelector(".modal-backdrop").addEventListener("click", closeAddModal);
saveRecipeBtn.addEventListener("click", saveNewRecipe);
cancelAddBtn.addEventListener("click", closeAddModal);

generatorBtn.addEventListener("click", openGeneratorModal);
closeGeneratorModalBtn.addEventListener("click", closeGeneratorModal);
generatorModal.querySelector(".modal-backdrop").addEventListener("click", closeGeneratorModal);
makeRecipeBtn.addEventListener("click", buildGeneratedRecipe);
cancelGeneratorBtn.addEventListener("click", closeGeneratorModal);

favouritesBtn.addEventListener("click", () => {
  state.favouritesOnly = !state.favouritesOnly;
  renderFilters();
  renderRecipes();
});

document.addEventListener("keydown", (e) => {
  if (e.key === "Escape") {
    closeRecipe();
    closeAddModal();
    closeGeneratorModal();
  }
});

surpriseBtn.addEventListener("click", () => {
  const filtered = recipes.filter(matchesRecipe);
  const pool = filtered.length ? filtered : recipes;
  const random = pool[Math.floor(Math.random() * pool.length)];
  openRecipe(random.id);
});

window.openRecipe = openRecipe;
window.closeRecipe = closeRecipe;
window.toggleFavourite = toggleFavourite;

renderFilters();
renderRecipes();


